    background: #f2f2f2;
    padding: 8px 14px;
    border-radius: 6px;
    font-size: 0.9em;
    text-decoration: none;
    color: #444 !important;
}

.blog-pager a:hover,
#blog-pager a:hover {
    background: #e0e0e0;
}

/* 10. HIDE FEED LINKS AND OUTER FOOTER */
.feed-links,
.footer-outer {
    display: none !important;
}

/* 11. GLOBAL CLEANUP */
h1, h2, h3, p, .post-body, .post {
    text-align: left !important;
}

/* 12. MOBILE TIGHTENING */
@media screen and (max-width: 768px) {
    body {
        padding: 25px 15px !important;
    }

    .post-body p {
        margin-bottom: 1.2em !important;
    }

    .post-body {
        margin-bottom: 15px !important;
    }

    h1, h2, h3 {
        margin-top: 20px !important;
        margin-bottom: 10px !important;
    }
}

/* 13. WIDER DESKTOP FEEL */
@media screen and (min-width: 1200px) {
    body {
        max-width: 820px !important;
    }
}

/* 14. PAGE-SPECIFIC TEXT TWEAKS */
.page .post-body p {
    margin-bottom: 1em !important;
    line-height: 1.7;
}

.page .post-body strong {
    color: #222 !important;
}

/* External link indicators */
.tabs-inner .widget-content a[href^="http"]:not([href*="andrewscaife.com"])::after,
.post-body a[href^="http"]:not([href*="andrewscaife.com"]):not(:has(img))::after,
.site-footer a[href^="http"]:not([href*="andrewscaife.com"])::after {
