    text-decoration: underline !important;
}


/* Hide archive date on the Home static page only */
body.page-type-static_page .archive-date {
  display: none !important;
}

/* Show archive date on label pages and search results */
body.is-label-page .archive-date,
body.is-search-results .archive-date {
