}

body.page-type-index .post-header,
body.page-type-index .post-footer,
body.page-type-index .post-body {
    display: none !important;
}

body.page-type-index .post-outer {
    margin: 0 0 14px 0 !important;
}

body.page-type-index .post-outer::before {
